#### Model Solution for Q.A(a):

```cpp
#include <iostream>
using namespace std;

class Employee {
private:                                 // (1 mark: visibility)
    double salary;                       // private data
    bool validateSalary(double s) {      // private helper (1 mark)
        return (s >= 0);
    }

public:                                  // (1 mark: visibility)
    string name;

    Employee(string n, double s) {       // Constructor
        name = n;
        if (validateSalary(s))           // (1 mark: internal use)
            salary = s;
        else
            salary = 0;
    }

    void setSalary(double s) {           // Public setter (2 marks)
        if (validateSalary(s)) {
            salary = s;
            cout << "Salary updated.\n";
        } else {
            cout << "Invalid salary! Rejected.\n";
        }
    }

    double getSalary() { return salary; }// Public getter (1 mark)
};

int main() {
    Employee e("Rahul", 50000);
    cout << "Name: " << e.name << "\n";          // ✅ public
    cout << "Initial: " << e.getSalary() << "\n";// ✅ via getter
    e.setSalary(60000);                          // ✅ valid
    e.setSalary(-1000);                          // ❌ rejected by validator
    // cout << e.salary;                         // ❌ COMPILE ERROR
    return 0;
}
```

