#### Model Solution — (a) [7 marks]

- **Block diagram (2 marks)** — draw the standard 3-box diagram showing arrows `User → View → Controller → Model` and a notification arrow `Model → View`.
- **Model (1.5 marks):** Holds account state (`balance`, `accountNo`); contains methods `deposit()`, `withdraw()`; **notifies** observers.
- **View (1.5 marks):** Swing JFrame with three text fields (account no, amount, balance) and two buttons (Deposit, Withdraw). Read-only display of balance.
- **Controller (2 marks):** Wires `ActionListener`s to buttons; on Deposit click reads amount, calls `model.deposit(amount)`, refreshes View balance field; similarly for Withdraw. **Does not store data** — only orchestrates.

#### Model Solution — (b) [7 marks]

```java
// MODEL
public class Account {
    private String accNo;
    private double balance;
    public Account(String a, double b) { this.accNo = a; this.balance = b; }
    public void deposit(double amt)  { if(amt>0) balance += amt; }
    public void withdraw(double amt) { if(amt>0 && amt<=balance) balance -= amt; }
    public double getBalance() { return balance; }
    public String getAccNo()   { return accNo; }
}

// VIEW
import javax.swing.*; import java.awt.*;
public class AccountView extends JFrame {
    JTextField txtAcc   = new JTextField(10);
    JTextField txtAmt   = new JTextField(10);
    JLabel     lblBal   = new JLabel("0.0");
    JButton    btnDep   = new JButton("Deposit");
    JButton    btnWdr   = new JButton("Withdraw");
    public AccountView() {
        setLayout(new GridLayout(4,2));
        add(new JLabel("Account No:")); add(txtAcc);
        add(new JLabel("Amount:"));     add(txtAmt);
        add(new JLabel("Balance:"));    add(lblBal);
        add(btnDep); add(btnWdr);
        pack(); setDefaultCloseOperation(EXIT_ON_CLOSE);
    }
    public String getAccNo()      { return txtAcc.getText(); }
    public double getAmount()     { return Double.parseDouble(txtAmt.getText()); }
    public void   setBalance(double b){ lblBal.setText(String.valueOf(b)); }
    public JButton getDepBtn()   { return btnDep; }
    public JButton getWdrBtn()   { return btnWdr; }
}

// CONTROLLER
import java.awt.event.*;
public class AccountController {
    private Account     model;
    private AccountView view;
    public AccountController(Account m, AccountView v){
        this.model = m; this.view = v;
        view.getDepBtn().addActionListener(e -> {
            model.deposit(view.getAmount());
            view.setBalance(model.getBalance());
        });
        view.getWdrBtn().addActionListener(e -> {
            model.withdraw(view.getAmount());
            view.setBalance(model.getBalance());
        });
        view.setBalance(model.getBalance());
    }
}

// DRIVER
public class BankMVC {
    public static void main(String[] a){
        Account m = new Account("B001", 1000.0);
        AccountView v = new AccountView();
        new AccountController(m, v);
        v.setVisible(true);
    }
}
```
*(7 marks — 2 for Model, 2 for View, 2 for Controller, 1 for Driver + correct execution trace)*

