## 3.3 Combined Analytical Exercise — JTextField + JDBC (Real KTU Pattern)

A typical **end-semester** or **lab exam** question asks you to build a form where a JTextField accepts a roll number, and on pressing Enter, fetches the student's name from a database.

### Program 3: Roll-Number Lookup Tool

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;
import java.sql.*;

public class StudentLookup extends JFrame implements ActionListener {

    JTextField rollField, nameField, cgpaField;
    JButton fetchButton;

    public StudentLookup() {
        setTitle("KTU Student Lookup Tool");
        setSize(350, 200);
        setLayout(new GridLayout(4, 2, 10, 10));
        setDefaultCloseOperation(EXIT_ON_CLOSE);

        add(new JLabel("Enter Roll No:"));
        rollField = new JTextField(10);
        add(rollField);

        add(new JLabel("Student Name:"));
        nameField = new JTextField(10);
        nameField.setEditable(false);            // Output field is read-only.
        add(nameField);

        add(new JLabel("CGPA:"));
        cgpaField = new JTextField(10);
        cgpaField.setEditable(false);
        add(cgpaField);

        fetchButton = new JButton("Fetch from DB");
        add(new JLabel());                       // Empty cell for alignment.
        add(fetchButton);

        fetchButton.addActionListener(this);
        rollField.addActionListener(this);        // Enter key also triggers fetch.

        setVisible(true);
    }

    @Override
    public void actionPerformed(ActionEvent e) {
        String roll = rollField.getText().trim();
        if (roll.isEmpty()) {
            JOptionPane.showMessageDialog(this, "Please enter a roll number.");
            return;
        }

        try (Connection conn = DriverManager.getConnection(
                "jdbc:mysql://localhost:3306/ktu_students", "root", "password123");
             PreparedStatement pstmt = conn.prepareStatement(
                "SELECT name, cgpa FROM students WHERE roll_no = ?")) {

            pstmt.setInt(1, Integer.parseInt(roll));
            try (ResultSet rs = pstmt.executeQuery()) {
                if (rs.next()) {
                    nameField.setText(rs.getString("name"));
                    cgpaField.setText(String.valueOf(rs.getDouble("cgpa")));
                } else {
                    nameField.setText("Not found");
                    cgpaField.setText("N/A");
                }
            }
        } catch (SQLException | NumberFormatException ex) {
            JOptionPane.showMessageDialog(this, "Error: " + ex.getMessage());
        }
    }

    public static void main(String[] args) {
        new StudentLookup();
    }
}
```

> [!IMPORTANT]
> **KTU Exam Tip:** This program uses **try-with-resources** (Java 7+) — a clean alternative to the `finally` block for automatic resource closing. If you write this in your exam, you earn **bonus cognitive credit** for demonstrating modern Java knowledge.

